from docx import Document
from docx.shared import Pt, RGBColor, Inches, Cm
from docx.enum.text import WD_ALIGN_PARAGRAPH
from docx.oxml.ns import qn
from docx.oxml import OxmlElement

doc = Document()

# ── Page margins ──────────────────────────────────────────────────────────────
for section in doc.sections:
    section.top_margin    = Cm(2.5)
    section.bottom_margin = Cm(2.5)
    section.left_margin   = Cm(2.8)
    section.right_margin  = Cm(2.8)

# ── Styles ────────────────────────────────────────────────────────────────────
normal_style = doc.styles['Normal']
normal_style.font.name = 'Arial'
normal_style.font.size = Pt(11)

# ── Helpers ───────────────────────────────────────────────────────────────────
BLUE   = RGBColor(0x1F, 0x4E, 0x79)
RED    = RGBColor(0x7B, 0x24, 0x1C)
GREEN  = RGBColor(0x1E, 0x84, 0x49)
GREY   = RGBColor(0x44, 0x44, 0x44)
BLACK  = RGBColor(0x00, 0x00, 0x00)

def add_cover_title(text, color=BLUE):
    p = doc.add_paragraph()
    p.alignment = WD_ALIGN_PARAGRAPH.CENTER
    run = p.add_run(text)
    run.bold = True
    run.font.size = Pt(20)
    run.font.color.rgb = color
    run.font.name = 'Arial'

def add_subtitle(text):
    p = doc.add_paragraph()
    p.alignment = WD_ALIGN_PARAGRAPH.CENTER
    run = p.add_run(text)
    run.italic = True
    run.font.size = Pt(12)
    run.font.color.rgb = GREY
    run.font.name = 'Arial'
    p.paragraph_format.space_after = Pt(4)

def add_essay_heading(n, title, color=BLUE):
    doc.add_page_break()
    p = doc.add_paragraph()
    run = p.add_run(f'Essay {n}')
    run.bold = True
    run.font.size = Pt(16)
    run.font.color.rgb = color
    run.font.name = 'Arial'
    p.paragraph_format.space_after = Pt(2)

    p2 = doc.add_paragraph()
    run2 = p2.add_run(title)
    run2.bold = True
    run2.italic = True
    run2.font.size = Pt(13)
    run2.font.color.rgb = GREY
    run2.font.name = 'Arial'
    p2.paragraph_format.space_after = Pt(8)

def add_question_box(q_text):
    p = doc.add_paragraph()
    run = p.add_run('Question: ')
    run.bold = True
    run.font.color.rgb = GREEN
    run.font.name = 'Arial'
    run.font.size = Pt(11)
    run2 = p.add_run(q_text)
    run2.italic = True
    run2.font.color.rgb = GREEN
    run2.font.name = 'Arial'
    run2.font.size = Pt(11)
    pf = p.paragraph_format
    pf.left_indent  = Inches(0.3)
    pf.space_before = Pt(4)
    pf.space_after  = Pt(12)

def add_section_label(label, color=BLUE):
    p = doc.add_paragraph()
    run = p.add_run(label)
    run.bold = True
    run.font.size = Pt(10)
    run.font.color.rgb = color
    run.font.name = 'Arial'
    run.font.all_caps = True
    p.paragraph_format.space_before = Pt(10)
    p.paragraph_format.space_after  = Pt(3)

def add_body(text, italic_runs=None):
    """italic_runs = list of substrings to italicise (titles)"""
    p = doc.add_paragraph()
    p.paragraph_format.space_after  = Pt(10)
    p.paragraph_format.first_line_indent = Inches(0)

    titles = ['Nineteen Eighty-Four', '1984', 'V for Vendetta']
    # Simple approach: split on known italic tokens
    import re
    pattern = '(' + '|'.join(re.escape(t) for t in titles) + ')'
    parts = re.split(pattern, text)
    for part in parts:
        r = p.add_run(part)
        r.font.name = 'Arial'
        r.font.size = Pt(11)
        r.font.color.rgb = BLACK
        if part in titles:
            r.italic = True

def add_divider():
    p = doc.add_paragraph('─' * 60)
    p.alignment = WD_ALIGN_PARAGRAPH.CENTER
    p.paragraph_format.space_before = Pt(6)
    p.paragraph_format.space_after  = Pt(6)
    for run in p.runs:
        run.font.color.rgb = GREY
        run.font.size = Pt(9)

